  ('cpa-moex-01618', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依現行公司法規定，關於公司債之私募，下列敘述何者錯誤？', '["採發行後報備制", "非公開發行公司不可為之", "私募人數原則上不得超過35人", "無過去年度獲利能力規定之適用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01619', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列何種情形A有限公司之法人格終局消滅？', '["董事長甲死亡，且無繼承人", "主管機關因A公司未於登記後6個月開始營業，或營業後停止營業超過6個月，而予以命令解散", "A有限公司之其他股東以公司經營顯有困難為理由，向法院聲請裁定解散，經法院裁定解散者", "經完成清算程序者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01620', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依公司法之規定，對於股份有限公司監察人之設置，下列敘述何者正確？', '["公開發行股票之公司監察人選舉，得依董事會決議採取候選人提名制度", "監察人全體均須在國內有住所", "公開發行股票之公司之監察人須有2人以上", "公司與監察人間之關係，從民法關於僱傭之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01621', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲股份有限公司為未公開發行股票之公司，對於該公司董事之解任，下列敘述何者正確？', '["股東會於董事之任期中，不得以決議將其解任", "股東會為解任董事之決議時，除公司章程對於出席股東股份總數及表決權數有較高之規定者外，應有 代表已發行股份總數三分之二以上股東之出席，以出席股東表決權過半數之同意行之", "股東會如於董事任期中無正當理由將其解任時，董事亦不得向公司請求賠償其損害", "董事執行業務，有重大損害公司之行為或違反法令或章程之重大事項，視為當然解任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01622', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '公司變更章程應以下列何種決議行之？', '["董事會普通決議", "董事會特別決議", "股東會普通決議", "股東會特別決議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01623', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '公司法第234條第1項所定之「建業股息」，其性質上屬於下列何者？', '["遞延股息", "預付股息", "信託股息", "絕對股息"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01624', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '對於常務董事及常務董事會之敘述，下列何者正確？', '["常務董事會分別為有限公司及股份有限公司之法定、任意設置之公司機關", "常務董事之名額至少3人，最多不得超過董事人數二分之一", "常務董事應由三分之二以上董事之出席，及出席董事過半數之同意，互選之", "常務董事於董事會休會時，依法令、章程、股東會決議及董事會決議，以集會方式經常執行董事會職 權，由董事長隨時召集，並應以三分之二以上常務董事之出席，及出席過半數之決議行之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01625', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '以下證券交易法第14條之6關於薪資報酬委員會規定之說明，何者正確？', '["上市上櫃公司須經章程規定方得設置薪資報酬委員會", "薪資報酬委員會之成員應由全體獨立董事組成", "本條所規範者係公司內領取高薪者之薪資報酬，與其所擔任之職務無關", "薪資報酬委員會之決議係供董事會決策參考"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01626', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列何者係屬於承銷方式之一？', '["代銷", "直銷", "傾銷", "經銷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01627', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '任何人單獨或與他人共同預定於50日內取得公開發行公司已發行股份總額達到何種比例者，原則上應採 公開收購方式為之？', '["百分之五十以上", "百分之四十以上", "百分之三十以上", "百分之二十以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01628', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列何者屬於證券交易法所稱之有價證券？', '["未經簽證之公司股票", "申購股票之中籤通知書及繳款通知書", "依不動產證券化條例所發行之受益證券", "未發行股票之公司股東所出具之股份轉讓證書"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01629', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '公開發行股票公司出席股東會委託書之取得，其徵求行為應遵守法令限制之規定，下列敘述何者錯誤？', '["除代為發放股東會紀念品或徵求人支付予代為處理徵求事務者之合理費用外，不得為以給付金錢或其 他利益價購為條件", "不得利用他人名義徵求", "不得將徵求之委託書作為非屬徵求之委託書出席股東會", "持未遵守法令限制規定之徵求委託書出席股東會行使表決權，該次股東會決議將因此無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01630', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '已依證券交易法發行股票公司之董事、監察人、經理人或持有公司股份超過股份總額百分之十之股東， 其股票之轉讓應依規定申報，而其申報之範圍包括利用他人名義持有股票，下列何者不是利用他人名義 持有股票之構成要件之一？', '["直接或間接提供股票與他人或提供資金與他人購買股票", "對該他人所持有之股票，具有管理、使用或處分之權益", "該他人所持有股票之利益或損失全部或一部歸屬於本人", "利用董事、監察人、經理人或持有公司股份超過股份總額百分之十之股東名義持有股票者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01631', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'X外國公司擬於我國發行臺灣存託憑證（TDR）。依證券交易法之規定，下列敘述何者正確？', '["臺灣存託憑證非證券交易法第6條所稱之有價證券", "X外國公司不必向主管機關申報或申請核准，即可自由在我國發行臺灣存託憑證", "X外國公司募集發行臺灣存託憑證，應先向應募人交付公開說明書", "X外國公司所發行之臺灣存託憑證不必向證券交易所申請，即可上市買賣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
